let blocked_t_ptr: ThreadPtr = pre_self_.get_endpoint(endpoint_ptr).queue@[0];
let blocked_c_ptr: ContainerPtr = pre_self_.get_thread(blocked_t_ptr).owning_container;

// Domain equalities first (both posts vs pre, then pre transitively links the two posts).
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.page_closure() =~= pre_self_.page_closure());
assert(post2_self_.page_closure() =~= pre_self_.page_closure());

assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

// Pointwise proc equality between the two posts.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr)
by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

// Container equality off the blocked container.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) && c_ptr != blocked_c_ptr
    implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr)
by {
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
}

// Container subtree_set always equal between the two posts.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr)
    implies post1_self_.get_container(c_ptr).subtree_set
        =~= post2_self_.get_container(c_ptr).subtree_set
by {
    assert(post1_self_.get_container(c_ptr).subtree_set
        =~= pre_self_.get_container(c_ptr).subtree_set);
    assert(post2_self_.get_container(c_ptr).subtree_set
        =~= pre_self_.get_container(c_ptr).subtree_set);
}

// Thread equality off the blocked thread.
// Multi-alt triggers: the ensures uses `pre_self_.get_thread(t_ptr)`, but the
// later goal will mention `postX_self_.get_thread(t_ptr)`. We list all three
// so the quantifier fires whichever side instantiates it.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    #![trigger post1_self_.get_thread(t_ptr)]
    #![trigger post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != blocked_t_ptr
    implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr)
by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
}

// Thread endpoint_descriptors always equal between the two posts.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    #![trigger post1_self_.get_thread(t_ptr)]
    #![trigger post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr)
    implies post1_self_.get_thread(t_ptr).endpoint_descriptors
        =~= post2_self_.get_thread(t_ptr).endpoint_descriptors
by {
    assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
        =~= post1_self_.get_thread(t_ptr).endpoint_descriptors);
    assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
        =~= post2_self_.get_thread(t_ptr).endpoint_descriptors);
}

// Endpoint equality off endpoint_ptr.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
    implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr)
by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
}

// Endpoint owning_container always equal between the two posts.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr)
    implies post1_self_.get_endpoint(e_ptr).owning_container
        =~= post2_self_.get_endpoint(e_ptr).owning_container
by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr).owning_container
        =~= post1_self_.get_endpoint(e_ptr).owning_container);
    assert(pre_self_.get_endpoint(e_ptr).owning_container
        =~= post2_self_.get_endpoint(e_ptr).owning_container);
}

// Specific equalities at the modified indices (the head of the endpoint
// queue: thread, owning container, and endpoint itself).
assert(post1_self_.get_thread(blocked_t_ptr).endpoint_descriptors
    =~= post2_self_.get_thread(blocked_t_ptr).endpoint_descriptors);

assert(post1_self_.get_container(blocked_c_ptr).owned_procs
    =~= post2_self_.get_container(blocked_c_ptr).owned_procs);
assert(post1_self_.get_container(blocked_c_ptr).owned_threads
    =~= post2_self_.get_container(blocked_c_ptr).owned_threads);
assert(post1_self_.get_container(blocked_c_ptr).children
    =~= post2_self_.get_container(blocked_c_ptr).children);
assert(post1_self_.get_container(blocked_c_ptr).subtree_set
    =~= post2_self_.get_container(blocked_c_ptr).subtree_set);

assert(post1_self_.get_endpoint(endpoint_ptr).queue@
    =~= pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
assert(post2_self_.get_endpoint(endpoint_ptr).queue@
    =~= pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
assert(post1_self_.get_endpoint(endpoint_ptr).queue@
    =~= post2_self_.get_endpoint(endpoint_ptr).queue@);
assert(post1_self_.get_endpoint(endpoint_ptr).owning_threads
    == post2_self_.get_endpoint(endpoint_ptr).owning_threads);
assert(post1_self_.get_endpoint(endpoint_ptr).rf_counter
    == post2_self_.get_endpoint(endpoint_ptr).rf_counter);
assert(post1_self_.get_endpoint(endpoint_ptr).queue_state
    == post2_self_.get_endpoint(endpoint_ptr).queue_state);
assert(post1_self_.get_endpoint(endpoint_ptr).owning_container
    =~= post2_self_.get_endpoint(endpoint_ptr).owning_container);
